#include <iostream>
using namespace std;
int n,I;
long func(int x)
{
    long ans=x;
    for(int i=0;i<=n-1;i++)
    { 
        ans=ans*n+I;
        if(i!=0)
        {
            ans = (ans-I);
            //cout << ans << "  " << (n-1) << "  " << ans%(n-1) << endl;
            if(ans%(n-1))
            {
                return func(x+1);
            } 
            else
            {
                ans=ans/(n-1)+I;
            }
        }
        //cout << ans << "  " << i << endl;
        // if (i == 0) {
        //     ans = ans * n + I;
        // } else {
        //     if (ans % (n-1)) {//不能除尽
        //         return func(x+1);
        //     } else {
        //         ans=ans/(n-1)*n+I;
        //     } 
        // }
    }
    //cout << x << endl;
    return ans;
}
int main() 
{
    cin>>n>>I;
    cout<<func(1);
    return 0;
}
